// --- Secret validation ---
const secret = $input.first().json.headers?.['x-webhook-secret'];
const expectedSecret = $env.WEBHOOK_SECRET;

if (!secret || secret !== expectedSecret) {
  throw new Error('Unauthorized: invalid or missing x-webhook-secret header');
}

// --- Parse body ---
const body = $input.first().json.body || $input.first().json;
const { type, payload, user_id, session_id } = body;

if (!type || !['text', 'audio', 'ocr'].includes(type)) {
  throw new Error('Invalid request: type must be "text", "audio", or "ocr"');
}
if (!user_id) {
  throw new Error('Invalid request: user_id is required');
}
if (!session_id) {
  throw new Error('Invalid request: session_id is required');
}
if (!payload || typeof payload !== 'object') {
  throw new Error('Invalid request: payload object is required');
}

// --- In-memory rate limit (max 20 requests per user per minute) ---
// Uses global static map persisted across executions within the same process
if (!global.rateLimitMap) {
  global.rateLimitMap = {};
}
const now = Date.now();
const windowMs = 60 * 1000; // 1 minute
const maxRequests = 20;

if (!global.rateLimitMap[user_id]) {
  global.rateLimitMap[user_id] = [];
}

// Evict timestamps outside the current window
global.rateLimitMap[user_id] = global.rateLimitMap[user_id].filter(
  ts => now - ts < windowMs
);

if (global.rateLimitMap[user_id].length >= maxRequests) {
  throw new Error(`Rate limit exceeded: user ${user_id} has sent ${maxRequests} requests in the last minute`);
}

global.rateLimitMap[user_id].push(now);

return [{
  json: {
    type,
    payload,
    user_id,
    session_id
  }
}];

// Pull validated data from the Validate node (step 2)
const validated = $('Validate + Rate Limit').first().json;
const { type, payload, user_id, session_id } = validated;

// Pull history from Supabase (step 3)
const historyItems = $input.first().json;
const history = Array.isArray(historyItems) ? historyItems : [];

// Build history context string
let historyContext = '';
if (history.length > 0) {
  historyContext = '\n\nRecent session history (last 5 corrections for this student):\n';
  history.forEach((msg, i) => {
    const original = msg.original_text || msg.original || '';
    const corrected = msg.corrected_text || msg.corrected || '';
    const created = msg.created_at ? new Date(msg.created_at).toLocaleDateString('de-DE') : '';
    historyContext += `${i + 1}. [${created}] Original: "${original}" → Corrected: "${corrected}"\n`;
  });
}

// Detect recurring error patterns from history
let patternNote = '';
if (history.length >= 2) {
  patternNote = '\nNote: Based on this student\'s history, pay special attention to patterns of repeated errors (e.g., consistent case mistakes, recurring verb conjugation errors, or repeated preposition misuse). Highlight if this submission repeats a previously corrected error.';
}

// Construct personalized system prompt
const systemPrompt = `You are Morodeutsch, a warm and encouraging German language tutor specializing in teaching Moroccan students. You understand the linguistic challenges Arabic and Darija speakers face when learning German (e.g., definite article gender, verb-second word order, case declension).

Your task: analyze the student's German submission, correct it, and provide a pedagogically sound explanation in simple English (with occasional Darija/French encouragement phrases where natural).

Always respond with a single valid JSON object in this exact format:
{
  "original": "<the student's original text>",
  "corrected": "<the fully corrected German text>",
  "explanation": "<clear explanation of each correction made, referencing specific grammar rules>",
  "cefr_estimate": "<estimated CEFR level: A1, A2, B1, B2, C1, or C2>",
  "encouragement": "<a short, genuine motivational message in English with one phrase in German or Darija>"
}

Guidelines:
- Be specific about corrections (e.g., "Article 'der' → 'die' because 'Sprache' is feminine")
- Estimate CEFR level based on vocabulary range, grammatical complexity, and error frequency
- Keep encouragement authentic, not generic
- If the text is already correct, say so and still provide cefr_estimate and encouragement
- Do NOT wrap the JSON in markdown code fences${historyContext}${patternNote}`;

return [{
  json: {
    systemPrompt,
    type,
    payload,
    user_id,
    session_id
  }
}];

