// Pick the successful transcription (Azure primary, Groq fallback)
const azureResult = $('Azure Whisper STT').first()?.json;
const groqResult = $('Groq Whisper Fallback').first()?.json;

const transcribedText =
  (azureResult && !azureResult.error && azureResult.text) ||
  (groqResult && !groqResult.error && groqResult.text) ||
  '';

if (!transcribedText) {
  throw new Error('Audio transcription failed on both Azure Whisper and Groq. Please try again or submit text directly.');
}

const buildPromptData = $('Build System Prompt').first().json;

return [{
  json: {
    ...buildPromptData,
    payload: {
      ...buildPromptData.payload,
      transcribed_text: transcribedText
    }
  }
}];

// The Azure Vision Read API returns an Operation-Location header;
// for simplicity here we use the base64 image path via the image_base64 field
// which is sent directly to GPT-4o Vision for in-context OCR.

// Pull from Build System Prompt context
const buildPromptData = $('Build System Prompt').first().json;
const imageBase64 = buildPromptData.payload.image_base64 || '';

if (!imageBase64) {
  throw new Error('OCR request missing image_base64 in payload');
}

// We will pass the base64 image directly to GPT-4o vision endpoint
return [{
  json: {
    ...buildPromptData,
    payload: {
      ...buildPromptData.payload,
      image_base64: imageBase64
    }
  }
}];

