// This node normalizes output from ALL three branches (text, audio, ocr)
// into a single unified shape.

// Detect which branch produced output by checking which upstream node has data
let rawContent = '';
let inputType = 'text';
let originalInput = '';

// Try to pull from audio branch first
try {
  const audioGptData = $('Azure GPT-4o Audio Correct').first()?.json;
  if (audioGptData && audioGptData.choices) {
    rawContent = audioGptData.choices[0]?.message?.content || '';
    inputType = 'audio';
    originalInput = $('Resolve Transcription').first()?.json?.payload?.transcribed_text || '';
  }
} catch (e) {}

// Try OCR branch
if (!rawContent) {
  try {
    const ocrGptData = $('Azure GPT-4o Vision OCR').first()?.json;
    if (ocrGptData && ocrGptData.choices) {
      rawContent = ocrGptData.choices[0]?.message?.content || '';
      inputType = 'ocr';
      originalInput = $('Build System Prompt').first()?.json?.payload?.image_base64 ? '[image submitted]' : '';
    }
  } catch (e) {}
}

// Try text branch — Azure GPT primary
if (!rawContent) {
  try {
    const azureData = $('Azure GPT-4o').first()?.json;
    if (azureData && azureData.choices) {
      rawContent = azureData.choices[0]?.message?.content || '';
      inputType = 'text';
      originalInput = $('Build System Prompt').first()?.json?.payload?.text || '';
    }
  } catch (e) {}
}

// Try text branch — OpenRouter fallback
if (!rawContent) {
  try {
    const orData = $('OpenRouter Fallback').first()?.json;
    if (orData && orData.choices) {
      rawContent = orData.choices[0]?.message?.content || '';
      inputType = 'text';
      originalInput = $('Build System Prompt').first()?.json?.payload?.text || '';
    }
  } catch (e) {}
}

if (!rawContent) {
  throw new Error('All AI endpoints failed to produce a response. Please retry.');
}

// Parse JSON from AI response
let parsed;
try {
  // Strip markdown code fences if present
  const cleaned = rawContent.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback: wrap raw content
  parsed = {
    original: originalInput,
    corrected: rawContent,
    explanation: 'The AI response could not be parsed as structured JSON. Raw response returned.',
    cefr_estimate: 'B1',
    encouragement: 'Keep going! Mach weiter so!'
  };
}

// Ensure all required fields are present
const normalized = {
  original: parsed.original || originalInput,
  corrected: parsed.corrected || '',
  explanation: parsed.explanation || '',
  cefr_estimate: parsed.cefr_estimate || 'B1',
  encouragement: parsed.encouragement || 'Sehr gut! Keep practicing!',
  input_type: inputType,
  session_id: $('Build System Prompt').first()?.json?.session_id || '',
  user_id: $('Build System Prompt').first()?.json?.user_id || '',
  timestamp: new Date().toISOString()
};

return [{ json: normalized }];
